[ExtensionOf(ClassStr(CustAgingReportUIBuilder))]
final class ETG_CustAgingReportUIBuilder_Extension
{
    public CustAgingReportContract contract;
    public DialogField  financialDimensions;
    public DialogField  financialDimSet;
    public DialogField  detailed;

}

Method.Source:
public void postBuild()
{
    DialogField dialogField;

    next postBuild();

    financialDimensions = this.bindInfo().getDialogField(contract, methodStr(CustAgingReportContract, parmFinancialDimensions));
    financialDimensions.registerOverrideMethod(methodStr(FormCheckBoxControl, modified), methodStr(ETG_CustAgingReportUIBuilder_Extension, financialDimensionsModified), this);
    financialDimSet = this.bindInfo().getDialogField(contract, methodStr(CustAgingReportContract, parmFinancialDimSet));
    detailed = this.bindInfo().getDialogField(contract, methodStr(CustAgingReportContract, parmDetailed));
    detailed.registerOverrideMethod(methodStr(FormCheckBoxControl, modified), methodStr(ETG_CustAgingReportUIBuilder_Extension, detailedModified), this);
}

public boolean financialDimensionsModified(FormCheckBoxControl _control)
{
    if (_control.modified())
    {
        if (_control.value() == 1)
        {
            financialDimSet.enabled(true);
        }
        else
        {
            financialDimSet.enabled(false);
            financialDimSet.value("");
            contract.parmFinancialDimSet("");
        }
    }

    return  true;
}

public boolean detailedModified(FormCheckBoxControl _control)
{
    if (_control.modified())
    {
        if (_control.value() == 0)
        {
            financialDimensions.value(0);
            contract.parmFinancialDimensions(0);
            financialDimensions.enabled(false);
            financialDimSet.enabled(false);
            financialDimSet.value("");
            contract.parmFinancialDimSet("");
        }
        else
        {
            financialDimensions.enabled(true);
            if (financialDimensions.value() == 1)
            {
                financialDimSet.enabled(true);
            }
            else
            {
                financialDimSet.enabled(false);
                financialDimSet.value("");
                contract.parmFinancialDimSet("");
            }
        }
    }

    return  true;
}

/// <summary>
///    creating dimension sets lookup
/// </summary>
/// <param name = "_formStringControl">form string control</param>
public void finDimSetLookup(FormStringControl   _formStringControl)
{
    Query                   query = new Query();
    QueryBuildDataSource    qbds;
    SysTableLookup          sysTableLookup = SysTableLookup::newParameters(tablenum(DimensionHierarchy), _formStringControl);

    sysTableLookup.addLookupfield(fieldNum(DimensionHierarchy, Name));
    sysTableLookup.addLookupfield(fieldNum(DimensionHierarchy, Description));

    qbds = query.addDataSource(tableNum(DimensionHierarchy));
    qbds.addRange(fieldNum(DimensionHierarchy, StructureType)).value(queryValue(DimensionHierarchyType::Focus));
    qbds.addRange(fieldNum(DimensionHierarchy, IsSystemGenerated)).value(queryValue(NoYes::No));

    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();
}

/// <summary>
///
/// </summary>
public void build()
{
    next build();

    contract = this.dataContractObject();
    financialDimensions = this.bindInfo().getDialogField(contract, methodStr(CustAgingReportContract, parmFinancialDimensions));
    financialDimSet     = this.addDialogField(methodstr(CustAgingReportContract, parmFinancialDimSet), contract);
    detailed            = this.bindInfo().getDialogField(contract, methodStr(CustAgingReportContract, parmDetailed));
    if (detailed.value() == 0)
    {
        financialDimensions.value(0);
        contract.parmFinancialDimensions(0);
        financialDimensions.enabled(false);
    }
    else
    {
        financialDimensions.enabled(true);
    }

    if (financialDimensions.value() == 1)
    {
        financialDimSet.enabled(true);
    }
    else
    {
        financialDimSet.enabled(false);
        financialDimSet.value("");
        contract.parmFinancialDimSet("");
    }
}
